const SYSTEM_INSTRUCTION = `
Eres el "Cerebro Digital" de una Agencia de Marketing líder. 
Tu objetivo es demostrar a los prospectos cómo puedes atender sus negocios.
Responde de manera profesional, persuasiva y técnica sobre Meta Ads, automatizaciones de WhatsApp y IA.
Mantén las respuestas concisas (máximo 3 párrafos).
Si te preguntan por precios, menciona que tenemos un setup de $800 y un mantenimiento de $377/mes.
Tu nombre es "DigitalBrain v3".
`;

export const getGeminiResponse = async (userMessage: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: userMessage,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.95,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Lo siento, mi conexión neuronal está experimentando latencia. Por favor, intenta de nuevo o agenda una auditoría directa.";
  }
};

